import { _decorator, Component, Node, Event } from 'cc';
import { mEmitter } from './mEmitter';
import { EventType } from './Constants'; 
const { ccclass, property } = _decorator;

@ccclass('CharItem')
export class CharItem extends Component {

    protected onLoad(): void {
        new mEmitter();
        mEmitter.instance.registerOnce(EventType.DISABLE, this.toEnable.bind(this), this.node)
        mEmitter.instance.registerOnce(EventType.ENABLE, this.toEnable.bind(this), this.node)
    }

    start() {

    }

    update(deltaTime: number) {

    }

    toEnable(event: Event) {
        if (event.type === EventType.DISABLE) {
            this.node.active = false;
        } else if (event.type === EventType.ENABLE) {
            this.node.active = true;
        }
    }


}

